import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { ShoppingCart, Filter, Copy, Check } from 'lucide-react';

const fmt = (n) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 2 }).format(n);
const fmtDate = (d) => new Date(d).toLocaleDateString('en-IN', { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });

const statusStyle = (s) => ({
  Completed: { background: '#d1fae5', color: '#065f46' },
  Pending:   { background: '#fef3c7', color: '#92400e' },
  Failed:    { background: '#fee2e2', color: '#991b1b' },
}[s] || { background: '#f1f5f9', color: '#475569' });

function PartnerSales() {
  const [sales, setSales] = useState([]);
  const [filteredSales, setFilteredSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [copiedKey, setCopiedKey] = useState(null);

  useEffect(() => { loadSales(); }, []);
  useEffect(() => {
    setFilteredSales(statusFilter === 'All' ? sales : sales.filter(s => s.paymentStatus === statusFilter));
  }, [sales, statusFilter]);

  const loadSales = async () => {
    try {
      setLoading(true);
      const r = await partnerService.getSales();
      setSales(r.data);
    } catch { setError('Failed to load sales'); }
    finally { setLoading(false); }
  };

  const copyKey = (key, id) => {
    navigator.clipboard.writeText(key);
    setCopiedKey(id);
    setTimeout(() => setCopiedKey(null), 2000);
  };

  const totalRevenue = filteredSales.reduce((s, x) => s + x.saleAmount, 0);
  const totalCommission = filteredSales.reduce((s, x) => s + x.commissionAmount, 0);
  const paidCommission = filteredSales.filter(x => x.paymentStatus === 'Completed').reduce((s, x) => s + x.commissionAmount, 0);

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', color: '#64748b', fontSize: '1.1rem' }}>
      Loading sales...
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#f1f5f9', minHeight: '100vh' }}>
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '2rem', fontWeight: '700', color: '#1e293b', marginBottom: '0.25rem' }}>My Sales</h1>
        <p style={{ color: '#64748b' }}>Track all your sales and commissions</p>
      </div>

      {error && <div style={{ background: '#fef2f2', border: '1px solid #fecaca', borderRadius: '10px', padding: '1rem', marginBottom: '1.5rem', color: '#dc2626' }}>{error}</div>}

      {/* Summary Cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(190px, 1fr))', gap: '1.25rem', marginBottom: '2rem' }}>
        {[
          { label: 'Total Sales', value: filteredSales.length, big: true },
          { label: 'Total Revenue', value: fmt(totalRevenue) },
          { label: 'Total Commission', value: fmt(totalCommission) },
          { label: 'Paid Commission', value: fmt(paidCommission), green: true },
        ].map(c => (
          <div key={c.label} style={{ background: 'white', padding: '1.5rem', borderRadius: '14px', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', border: '1px solid #e2e8f0' }}>
            <p style={{ fontSize: '0.75rem', color: '#64748b', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '0.5rem' }}>{c.label}</p>
            <p style={{ fontSize: c.big ? '2rem' : '1.4rem', fontWeight: '700', color: c.green ? '#10b981' : '#1e293b', margin: 0 }}>{c.value}</p>
          </div>
        ))}
      </div>

      {/* Filter */}
      <div style={{ background: 'white', padding: '1rem 1.5rem', borderRadius: '12px', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '1rem', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', border: '1px solid #e2e8f0' }}>
        <Filter size={18} color="#64748b" />
        <label style={{ fontWeight: '600', color: '#475569', fontSize: '0.9rem' }}>Status:</label>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} style={{ padding: '0.5rem 1rem', border: '2px solid #e2e8f0', borderRadius: '8px', fontSize: '0.9rem', fontWeight: '500', color: '#1e293b', outline: 'none', background: 'white', cursor: 'pointer' }}>
          <option value="All">All</option>
          <option value="Pending">Pending</option>
          <option value="Completed">Completed</option>
          <option value="Failed">Failed</option>
        </select>
      </div>

      {/* Table */}
      {filteredSales.length === 0 ? (
        <div style={{ background: 'white', borderRadius: '14px', padding: '4rem 2rem', textAlign: 'center', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', border: '1px solid #e2e8f0' }}>
          <ShoppingCart size={48} color="#cbd5e1" style={{ margin: '0 auto 1rem' }} />
          <p style={{ fontSize: '1.1rem', fontWeight: '600', color: '#64748b', marginBottom: '0.5rem' }}>No Sales Found</p>
          <p style={{ color: '#94a3b8', fontSize: '0.9rem' }}>{statusFilter === 'All' ? "You haven't made any sales yet." : `No ${statusFilter.toLowerCase()} sales found.`}</p>
        </div>
      ) : (
        <div style={{ background: 'white', borderRadius: '14px', boxShadow: '0 1px 4px rgba(0,0,0,0.07)', border: '1px solid #e2e8f0', overflow: 'hidden' }}>
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
              <thead>
                <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
                  {['Date', 'Product', 'Buyer', 'Amount', 'Commission', 'Status', 'License Key', 'Notes'].map(h => (
                    <th key={h} style={{ padding: '1rem 1.25rem', textAlign: 'left', fontSize: '0.75rem', fontWeight: '700', color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.5px', whiteSpace: 'nowrap' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filteredSales.map(sale => (
                  <tr key={sale.saleId} style={{ borderBottom: '1px solid #f1f5f9', transition: 'background 0.15s' }}
                    onMouseEnter={e => e.currentTarget.style.background = '#f8fafc'}
                    onMouseLeave={e => e.currentTarget.style.background = 'white'}>
                    <td style={{ padding: '1rem 1.25rem', color: '#64748b', whiteSpace: 'nowrap' }}>{fmtDate(sale.saleDate)}</td>
                    <td style={{ padding: '1rem 1.25rem', fontWeight: '600', color: '#1e293b' }}>{sale.productName}</td>
                    <td style={{ padding: '1rem 1.25rem' }}>
                      <div style={{ fontWeight: '600', color: '#1e293b' }}>{sale.buyerName}</div>
                      <div style={{ fontSize: '0.78rem', color: '#94a3b8' }}>{sale.buyerEmail}</div>
                      {sale.buyerCompany && <div style={{ fontSize: '0.75rem', color: '#94a3b8' }}>{sale.buyerCompany}</div>}
                    </td>
                    <td style={{ padding: '1rem 1.25rem', fontWeight: '600', color: '#3b82f6', whiteSpace: 'nowrap' }}>{fmt(sale.saleAmount)}</td>
                    <td style={{ padding: '1rem 1.25rem', fontWeight: '600', color: '#10b981', whiteSpace: 'nowrap' }}>{fmt(sale.commissionAmount)}</td>
                    <td style={{ padding: '1rem 1.25rem' }}>
                      <span style={{ padding: '0.375rem 0.75rem', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '600', ...statusStyle(sale.paymentStatus) }}>{sale.paymentStatus}</span>
                    </td>
                    <td style={{ padding: '1rem 1.25rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <code style={{ padding: '0.25rem 0.5rem', background: '#f1f5f9', borderRadius: '6px', fontSize: '0.75rem', color: '#475569', border: '1px solid #e2e8f0', fontFamily: 'monospace' }}>{sale.licenseKey}</code>
                        <button onClick={() => copyKey(sale.licenseKey, sale.saleId)} style={{ background: 'none', border: '1px solid #e2e8f0', padding: '0.25rem', borderRadius: '4px', cursor: 'pointer', display: 'flex', alignItems: 'center', color: copiedKey === sale.saleId ? '#10b981' : '#94a3b8' }}>
                          {copiedKey === sale.saleId ? <Check size={14} /> : <Copy size={14} />}
                        </button>
                      </div>
                    </td>
                    <td style={{ padding: '1rem 1.25rem', color: '#64748b', fontSize: '0.85rem', maxWidth: '150px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{sale.notes || '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div style={{ padding: '0.75rem 1.25rem', borderTop: '1px solid #f1f5f9', textAlign: 'right', color: '#94a3b8', fontSize: '0.8rem' }}>
            Showing {filteredSales.length} of {sales.length} sales
          </div>
        </div>
      )}
    </div>
  );
}

export default PartnerSales;
